import "./input.css";

import { cn } from "tailwind-variants";

import { inputVariants, type InputVariants } from "./input.variants";

export type InputProps = InputVariants & React.ComponentProps<"input">;

export const Input = ({ className, ...props }: InputProps) => {
  return <input className={cn(inputVariants(), className)} {...props} />;
};

import { tv, type VariantProps } from "tailwind-variants";

export const inputVariants = tv({
  base: "input",
});

export type InputVariants = VariantProps<typeof inputVariants>;

.input {
  @apply border-input bg-background text-foreground placeholder:text-muted-foreground flex h-9 w-full rounded-md border px-3 py-1 text-sm shadow-sm transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }
}

import { Input, type InputProps } from "./input";
import { type InputVariants, inputVariants } from "./input.variants";

export { Input, inputVariants };

export type { InputProps, InputVariants };
